mapper.select:
select count(*) from UB_NOTICEBOARD 
WHERE board_date BETWEEN TO_DATE(#{dateFrom}, 'YYYY-MM-DD') AND TO_DATE(#{dateTo}, 'YYYY-MM-DD')
AND BOARD_TYPE = #{boardType}


SELECT * FROM (
	SELECT ROWNUM AS rnum, subquery.*
	FROM (
		SELECT unb.NOTICEBOARD_NUMBER , unb.board_title, unb.board_click, unb.board_date, unb.board_type, ua.ADMIN_NICKNAME 
		FROM UB_NOTICEBOARD unb
		LEFT JOIN UB_ADMIN UA ON unb.admin_number = ua.admin_number
		ORDER BY unb.NOTICEBOARD_NUMBER desc
	) subquery
)WHERE rnum BETWEEN #{startRow} AND #{endRow}


SELECT * FROM (
    SELECT ROWNUM AS rnum, subquery.*
    FROM (
        SELECT unb.*, ua.ADMIN_NICKNAME
        FROM UB_NOTICEBOARD unb
        LEFT JOIN UB_ADMIN ua ON unb.admin_number = ua.admin_number
		WHERE unb.board_date BETWEEN TO_DATE(#{dateFrom}, 'YYYY-MM-DD') AND TO_DATE(#{dateTo}, 'YYYY-MM-DD')
		AND unb.BOARD_TYPE = #{boardType}
        ORDER BY unb.NOTICEBOARD_NUMBER DESC
    ) subquery
)WHERE rnum BETWEEN #{startRow} AND #{endRow}


SELECT * FROM (
    SELECT ROWNUM AS rnum, subquery.*
    FROM (
        SELECT unb.*, ua.ADMIN_NICKNAME
        FROM UB_NOTICEBOARD unb
        LEFT JOIN UB_ADMIN ua ON unb.admin_number = ua.admin_number
		WHERE unb.board_date BETWEEN TO_DATE(#{dateFrom}, 'YYYY-MM-DD') AND TO_DATE(#{dateTo}, 'YYYY-MM-DD')
        ORDER BY unb.NOTICEBOARD_NUMBER DESC
    ) subquery
)WHERE rnum BETWEEN #{startRow} AND #{endRow}


